UPDATE account
SET email = #{email}, firstname = #{firstname}, lastname = #{lastname},
    status = #{status}, addr1 = #{addr1}, addr2 = #{addr2},
    city = #{city}, state = #{state}, zip = #{zip}, country = #{country}, phone = #{phone},
    role = #{role}
WHERE userid = #{userid}

UPDATE profile
SET langpref = #{langpref}, favcategory = #{favcategory},
    mylistopt = #{mylistopt}, banneropt = #{banneropt}
WHERE userid = #{userid}
